import { LngLat, Map } from "mapbox-gl";
import { IconManager, Fill, Line } from "@/index";

export function registerPlot(map: Map) {
  addIcon(map)
  if(true) {
    addFill(map)
  }
  if(false) {
    addLine(map)
  }
}

