function addLine(map: Map) {
  const position = [
    [
      122.08448264797659,
      30.001274472502857
    ],
    [
      122.08246562679733,
      29.99499333786683
    ],
    [
      122.0861992617468,
      29.991202164842264
    ],
    [
      122.09615562161054,
      29.990681796460322
    ],
    [
      122.10714194973406,
      29.990421611246077
    ],
    [
      122.10834357937438,
      29.998487035779164
    ],
    [
      122.09877345760799,
      30.003764516428134
    ],
  ].map(item => new LngLat(item[0], item[1]))

  const line = new Line(map, {
    id: '321',
    visibility: 'visible',
    position,
    vertexStyle: {
      'circle-radius': 5
    }
  })

  line.render()
  line.edit()
}

